// Policy service processor
//

pub trait PolicySyncHandler {
  fn handle_has(&self, user: i64, role: String) -> thrift::Result<bool>;
  fn handle_can(&self, user: i64, operation: String, resource: Resource) -> thrift::Result<bool>;
  fn handle_delete_user(&self, user: i64) -> thrift::Result<()>;
  fn handle_delete_role(&self, role: String) -> thrift::Result<()>;
  fn handle_get_roles_for_user(&self, user: i64) -> thrift::Result<BTreeSet<String>>;
  fn handle_get_implicit_roles_for_user(&self, user: i64) -> thrift::Result<BTreeSet<String>>;
  fn handle_get_users_for_role(&self, role: String) -> thrift::Result<BTreeSet<i64>>;
  fn handle_get_implicit_users_for_role(&self, role: String) -> thrift::Result<BTreeSet<i64>>;
  fn handle_add_roles_for_user(&self, user: i64, roles: BTreeSet<String>) -> thrift::Result<()>;
  fn handle_delete_roles_for_user(&self, user: i64, roles: BTreeSet<String>) -> thrift::Result<()>;
  fn handle_get_permissions_for_user(&self, user: i64) -> thrift::Result<BTreeSet<Permission>>;
  fn handle_get_implicit_permissions_for_user(&self, user: i64) -> thrift::Result<BTreeSet<Permission>>;
  fn handle_add_permissions_for_user(&self, user: i64, permissions: BTreeSet<Permission>) -> thrift::Result<()>;
  fn handle_delete_permissions_for_user(&self, user: i64, permissions: BTreeSet<Permission>) -> thrift::Result<()>;
  fn handle_get_permissions_for_role(&self, role: String) -> thrift::Result<BTreeSet<Permission>>;
  fn handle_get_implicit_permissions_for_role(&self, role: String) -> thrift::Result<BTreeSet<Permission>>;
  fn handle_add_permissions_for_role(&self, role: String, permissions: BTreeSet<Permission>) -> thrift::Result<()>;
  fn handle_delete_permissions_for_role(&self, role: String, permissions: BTreeSet<Permission>) -> thrift::Result<()>;
}

